using System;
using System.Linq;
using System.Threading.Tasks;
using Microsoft.EntityFrameworkCore;

public class EventBookingContext : DbContext
{
    public DbSet<Seat> Seats { get; set; }
    // Other DbSets...

    protected override void OnConfiguring(DbContextOptionsBuilder optionsBuilder)
    {
        optionsBuilder.UseSqlServer("YourConnectionStringHere");
    }
}

public class Seat
{
    public int Id { get; set; }
    public bool IsAvailable { get; set; }
    // Other properties...
}

public class EventBookingService
{
    private readonly EventBookingContext _context;

    public EventBookingService(EventBookingContext context)
    {
        _context = context;
    }

    public async Task<bool> PurchaseTicketsAsync(int seatId, int quantity)
    {
        var seatsToPurchase = await _context.Seats
            .Where(s => s.Id == seatId && s.IsAvailable)
            .Take(quantity)
            .ToListAsync();

        if (seatsToPurchase.Count < quantity)
        {
            return false;
        }

        foreach (var seat in seatsToPurchase)
        {
            seat.IsAvailable = false;
        }

        await _context.SaveChangesAsync();
        return true;
    }
}